{"code":"import json
import re

try:
    with open(locals()['var_function-call-1634184987777097794'], 'r') as f:
        papers = json.load(f)
except:
    papers = []

target_titles = [
    "A Trip to the Moon: Personalized Animated Movies for Self-reflection",
    "A Wee Bit More Interaction: Designing and Evaluating an Overactive Bladder App"
]

results = []

for paper in papers:
    filename = paper.get('filename', '')
    title = filename.replace('.txt', '')
    if title in target_titles:
        text = paper.get('text', '')

        # Find all 'empirical' matches
        matches = [m.start() for m in re.finditer(r'empirical', text, re.IGNORECASE)]
        snippets = []
        for start in matches:
            snippets.append(text[max(0, start-50):min(len(text), start+50)].replace('\n', ' '))

        results.append({
            "title": title,
            "snippets": snippets
        })

print("__RESULT__:")
print(json.dumps(results))"}
